const db = '/home/dooly/CronusFarm/data/cronusfarm.sqlite';
const sql = "SELECT b.id AS bed_id, b.code, b.name, b.sort_order, bl.id AS layer_id, bl.layer_no, bl.label, c.species, c.variety, c.planted_date, c.expected_harvest FROM bed b LEFT JOIN bed_layer bl ON bl.bed_id=b.id LEFT JOIN crop_assignment c ON c.bed_layer_id=bl.id WHERE b.active=1 ORDER BY b.sort_order, bl.layer_no";
try {
  const out = cp.execFileSync('sqlite3', ['-json', db, sql], { encoding: 'utf8', maxBuffer: 10*1024*1024, timeout: 15000 });
  msg.statusCode = 200;
  try { msg.payload = JSON.parse(out || '[]'); } catch (e) { msg.payload = []; }
} catch (e) {
  msg.statusCode = 500;
  msg.payload = { error: String(e.message || e) };
}
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const db = '/home/dooly/CronusFarm/data/cronusfarm.sqlite';
const opt = { encoding: 'utf8', timeout: 15000 };
let body = (msg.req && msg.req.body !== undefined && msg.req.body !== null) ? msg.req.body : msg.payload;
if (Buffer.isBuffer(body)) { try { body = JSON.parse(body.toString('utf8')); } catch (e) { msg.statusCode = 400; msg.payload = { error: 'JSON 파싱 실패' }; msg.headers = { 'Content-Type': 'application/json; charset=utf-8' }; return msg; } }
if (typeof body === 'string') { try { body = JSON.parse(body); } catch (e) { msg.statusCode = 400; msg.payload = { error: 'JSON 파싱 실패' }; msg.headers = { 'Content-Type': 'application/json; charset=utf-8' }; return msg; } }
if (!body || typeof body !== 'object') { msg.statusCode = 400; msg.payload = { error: '본문 필요' }; msg.headers = { 'Content-Type': 'application/json; charset=utf-8' }; return msg; }
const code = (body.code || '').toString().trim();
const name = (body.name || code).toString().trim();
if (!/^[A-Za-z][A-Za-z0-9_]{0,15}$/.test(code)) { msg.statusCode = 400; msg.payload = { error: 'code 형식: 영문 시작, 1~16자' }; msg.headers = { 'Content-Type': 'application/json; charset=utf-8' }; return msg; }
const q = (s) => String(s).replace(/'/g, "''");
const layers = Array.isArray(body.layers) ? body.layers : [{ layer_no: 1, label: '1층' }];
const ins = "INSERT INTO bed (code,name,sort_order) VALUES('" + q(code) + "','" + q(name) + "',900);";
try {
  cp.execFileSync('sqlite3', [db, ins], opt);
} catch (e) {
  const t = String(e.stderr || e.message || e);
  msg.statusCode = /UNIQUE|unique/.test(t) ? 409 : 500;
  msg.payload = { error: t || 'INSERT 실패' };
  msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
  return msg;
}
let bid;
try {
  const idOut = cp.execFileSync('sqlite3', [db, "SELECT id FROM bed WHERE code='" + q(code) + "';"], opt).trim();
  bid = parseInt(idOut, 10);
} catch (e) {
  msg.statusCode = 500;
  msg.payload = { error: String(e.message || e) };
  msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
  return msg;
}
for (const L of layers) {
  const no = parseInt(L.layer_no, 10) || 1;
  const lab = q((L.label || (String(no) + '층')).toString());
  const insL = "INSERT INTO bed_layer (bed_id,layer_no,label) VALUES(" + bid + "," + no + ",'" + lab + "');";
  try { cp.execFileSync('sqlite3', [db, insL], opt); } catch (e) { /* 무시 */ }
}
msg.statusCode = 201;
msg.payload = { ok: true, bed_id: bid, code, name };
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;
